// Parsear parametros de busqueda
const query = $input.first().json.query || {};

const q = query.q || '';                          // termino de busqueda
const categoria = query.categoria || '';          // filtro categoria
const provincia = query.provincia || '';          // filtro provincia
const limit = parseInt(query.limit) || 20;
const offset = parseInt(query.offset) || 0;

if (!q || q.length < 2) {
  return [{ json: { error: true, message: 'El parametro q es requerido (minimo 2 caracteres)' } }];
}

// Construir query params para Supabase
let supabaseUrl = `https://ygqfbbkjdiryilwjrpzh.supabase.co/rest/v1/latest_prices?`;
supabaseUrl += `canonical_name=ilike.*${encodeURIComponent(q)}*`;
if (categoria) supabaseUrl += `&category=eq.${encodeURIComponent(categoria)}`;
if (provincia) supabaseUrl += `&province=eq.${encodeURIComponent(provincia)}`;
supabaseUrl += `&order=price.asc`;
supabaseUrl += `&limit=${limit}&offset=${offset}`;

return [{ json: { supabaseUrl, q, categoria, provincia, limit, offset, valid: true } }];

const results = $input.first().json;
const prevParams = $('Parsear Query Params').first().json;
const arr = Array.isArray(results) ? results : [];

return [{
  json: {
    success: true,
    query: prevParams.q,
    total: arr.length,
    results: arr,
    meta: {
      categoria: prevParams.categoria || null,
      provincia: prevParams.provincia || null,
      limit: prevParams.limit,
      offset: prevParams.offset
    }
  }
}];

const query = $input.first().json.query || {};
const productId = query.product_id || '';

if (!productId) {
  return [{ json: { error: true, message: 'product_id es requerido' } }];
}

const supabaseUrl = `https://ygqfbbkjdiryilwjrpzh.supabase.co/rest/v1/latest_prices?product_id=eq.${productId}&order=price.asc`;

return [{ json: { supabaseUrl, product_id: productId, valid: true } }];

const results = $input.first().json;
const arr = Array.isArray(results) ? results : [];

if (arr.length === 0) {
  return [{ json: { success: true, product_id: $('Parsear Comparar').first().json.product_id, comparisons: [], cheapest: null } }];
}

const cheapest = arr[0];
const mostExpensive = arr[arr.length - 1];
const savings = mostExpensive.price - cheapest.price;
const savingsPct = ((savings / mostExpensive.price) * 100).toFixed(1);

return [{
  json: {
    success: true,
    product_name: arr[0].canonical_name,
    total_stores: arr.length,
    cheapest: {
      store: cheapest.store_name,
      price: cheapest.price,
      city: cheapest.city,
      url: cheapest.product_url
    },
    most_expensive: {
      store: mostExpensive.store_name,
      price: mostExpensive.price
    },
    potential_savings: savings,
    savings_percentage: savingsPct,
    comparisons: arr,
    updated_at: arr[0].scraped_at
  }
}];
